import { createMastra } from 'mastra';
import { VexMiddleware } from '@vex_dev/sdk';

const mastra = createMastra();

const vexMiddleware = new VexMiddleware({
  projectId: 'your-vex-project-id',
  apiKey: process.env.VEX_API_KEY!,
  rules: {
    verifyActionCorrectness: true,
    checkPermissions: true,
    ensureIdempotency: true
  }
});

const workflow = mastra.workflow('order-processing', {
  steps: [
    {
      id: 'fetch-order',
      type: 'tool',
      tool: 'orderApi.fetch',
      middleware: [vexMiddleware.validateInput()]
    },
    {
      id: 'check-approval',
      type: 'condition',
      condition: 'order.value > 1000',
      middleware: [vexMiddleware.validateTransition()],
      true: 'request-human-approval',
      false: 'process-order'
    }
  ]
});

import { Tool } from 'mastra';
import { VexMiddleware } from '@vex_dev/sdk';

const orderApiTool = new Tool({
  name: 'fetchOrder',
  description: 'Fetch order details',
  execute: async (orderId: string) => {
    const vex = new VexMiddleware({ /* config */ });

    // Permission validation
    await vex.validatePermission({
      action: 'api:order:read',
      resource: orderId,
      context: { workflowId: 'order-processing' }
    });

    const response = await fetch(`/api/orders/${orderId}`);
    const order = await response.json();

    // Output validation
    await vex.validateOutputSchema({
      schema: {
        type: 'object',
        properties: { id: { type: 'string' }, status: { type: 'string' } }
      },
      data: order
    });

    return order;
  }
});

import { AgentExecutor } from 'mastra';
import { VexMiddleware } from '@vex_dev/sdk';

const executor = new AgentExecutor(workflow);

const vex = new VexMiddleware({ /* config */ });

executor.onBeforeStep(async (step, context) => {
  // Check idempotency
  const idempotencyKey = `step:${step.id}:${context.executionId}`;
  const existingResult = await vex.getState(idempotencyKey);

  if (existingResult) {
    console.log('Step already executed, returning cached result');
    return existingResult;
  }

  // Execute with rollback capability
  return await vex.withRollback(
    async () => {
      const result = await step.execute(context);
      await vex.setState(idempotencyKey, result);
      return result;
    },
    { maxRetries: 3 }
  );
});

const approvalStep = {
  id: 'human-approval',
  type: 'human',
  prompt: (context) => `Approve this action? ${JSON.stringify(context.proposedAction)}`,
  middleware: [
    async (input, context) => {
      const vex = new VexMiddleware({ /* config */ });

      // Verify action correctness before human review
      const isValid = await vex.verifyAction({
        action: context.proposedAction,
        context: context.workflowState,
        rules: ['action_correctness', 'permission_validation']
      });

      if (!isValid) {
        throw new Error('Action verification failed');
      }

      return input;
    }
  ]
};

