import { createMastra } from 'mastra';
import { VexMiddleware } from '@vex_dev/sdk';

const vex = new VexMiddleware({
  projectId: 'your-project-id',
  rules: {
    validateTransitions: true,
    checkToolOutputs: true,
    verifyMemoryFreshness: true,
    ensureIdempotency: true
  }
});

const mastra = createMastra();
mastra.useGlobalMiddleware([
  vex.validateWorkflowInput(),
  vex.validateStepOutputs(),
  vex.checkMemoryContext(),
  vex.ensureRollbackSafety()
]);

// All workflows now automatically protected
export const protectedWorkflows = mastra.workflows;

const memoryMiddleware = async (input: any, context: any) => {
  const vex = new VexMiddleware({ /* config */ });

  // Check memory freshness (less than 1hr old)
  const memoryItems = await context.memoryStore.getRelevant();

  for (const item of memoryItems) {
    const isFresh = await vex.validateMemoryFreshness({
      item,
      maxAgeMs: 60 * 60 * 1000, // 1 hour
      context: context.workflowState
    });

    if (!isFresh) {
      console.warn(`Stale memory removed: ${item.id}`);
      await context.memoryStore.remove(item.id);
    }
  }

  return input;
};

const safeStepExecution = async (step: any, context: any) => {
  const vex = new VexMiddleware({ /* config */ });

  return vex.withRollback(async () => {
    // Pre-execution state capture
    const preState = await context.saveState();

    try {
      const result = await step.execute(context);

      // Post-execution validation
      await vex.validatePostCondition({
        stepId: step.id,
        result,
        expectedState: preState
      });

      return result;
    } catch (error) {
      // Automatic rollback
      await context.restoreState(preState);
      throw error;
    }
  }, {
    rollbackTimeout: 30000,
    maxRetries: 2
  });
};
